// V2 origin: CS:GO "Delete Console" (BeforeServiceStarted) — deletes csgo/console.log
// and prunes log files older than 7 days from csgo/0.
//
// V2 used the flat no-DB-access variable `ThisService_RootDirectory`; V3 loads the full
// entity, so this becomes `ThisService.RootDirectory`.
using System;
using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string consoleLog = Path.Combine(ThisService.RootDirectory, "csgo", "console.log");
if (File.Exists(consoleLog))
{
    File.Delete(consoleLog);
}

// Delete log files older than 7 days inside <RootDirectory>/csgo/0
string logDir = Path.Combine(ThisService.RootDirectory, "csgo", "0");
if (!Directory.Exists(logDir))
{
    return;
}

DateTime cutoff = DateTime.UtcNow.AddDays(-7);

foreach (var filePath in Directory.EnumerateFiles(logDir))
{
    DateTime creationTime;
    try
    {
        creationTime = File.GetCreationTimeUtc(filePath);
    }
    catch (Exception)
    {
        ScriptConsole.WriteLine($"Could not get creation time for {filePath}");
        continue;
    }

    if (creationTime <= cutoff)
    {
        try
        {
            File.Delete(filePath);
        }
        catch (Exception e)
        {
            ScriptConsole.WriteLine($"Could not remove CSGO logfile {filePath}: {e.Message}");
        }
    }
}

//refAssemblies: TCAdmin.Web.Shared.dll
// V2 origin: CS:GO "Update to beta version" (CustomServiceIcon, stops service).
//
// V2 shelled out to Monitor\Tools\SteamCmd\steamcmd.exe with a hardcoded path and
// "+app_update 740 -beta <betaversion> validate". That path and invocation no longer
// exist in V3. The V3-correct way is to drive the built-in Steam update pipeline
// (GameServiceManager.RunServiceSteamUpdate), which stops the service, runs the
// configured Steam tool (SteamCmd or DepotDownloader) for the right OS, then restarts.
//
// HOW THE BRANCH IS APPLIED IN V3 (config dependency — IMPORTANT):
// RunServiceSteamUpdate resolves the Steam branch from Game.SteamConfig.Branch, which
// supports ${...} template tokens evaluated against the service's Variables. For this
// script to actually switch branch, set the game's Steam "Branch" field to
// ${betaversion} (and Branch Password if the branch needs one). This script writes the
// chosen value into the service's `betaversion` variable, persists it, then runs the
// update. If Branch is left blank, the update will run on the default branch.
using System;
using System.Threading.Tasks;
using TCAdmin.SDK.Models;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string version = ThisService.Variables["betaversion"] as string ?? string.Empty;
string ipport = $"{ThisService.IPAddress}{ThisService.GamePort}";

// Persist betaversion so the ${betaversion} token in Game.SteamConfig.Branch resolves.
ThisService.Variables["betaversion"] = version;
await GameServiceManager.UpdateAsync(ThisService, true, ThisCancellationToken);

ScriptConsole.WriteLine($"Installing version {version} on {ipport}...");

var handlers = new ProgressHandlers
{
    OnProgress = pct => { ScriptConsole.WriteLine($"Progress: {pct}%"); return Task.CompletedTask; },
    OnMessage = (msg, collapseKey) => { ScriptConsole.WriteLine(msg); return Task.CompletedTask; },
    OnDebugMessage = (msg, collapseKey) => { ScriptConsole.WriteLine(msg); return Task.CompletedTask; },
};

var result = await GameServiceManager.RunServiceSteamUpdate(ThisService.ServiceId, handlers, ThisCancellationToken);
if (!result.Success)
{
    throw new Exception(result.Message ?? "Steam update failed");
}

ScriptConsole.WriteLine("Done.");

//refAssemblies: TCAdmin.Web.Shared.dll
// V2 origin: CS:GO "Extract mapfile" (AfterCustomModInstalled).
//
// IMPORTANT BEHAVIORAL NOTE (read before deploying):
// In V2 a workshop custom-map download produced a SINGLE compressed blob at the bare
// script variable `FileNameSavePath` (filename in `FileNameNoPath`). The V2 script
// renamed that blob to .zip and extracted it into csgo/maps.
//
// V3 has NO `FileNameSavePath` / `FileNameNoPath` variables. The workshop pipeline
// (SteamCmd / DepotDownloader) downloads the item already-extracted into a DIRECTORY,
// surfaced to the script as `Dynamic.InstallPath`
// (= <RootDirectory>/steamapps/[Ww]orkshop/content/<storeId>/<fileId>/).
// So the correct V3 port is: copy the map asset files (.bsp/.nav/.ain/.txt) out of
// InstallPath into csgo/maps. No rename-to-zip / decompress step is needed.
using System;
using System.IO;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string installPath = (string)Dynamic.InstallPath;
if (string.IsNullOrEmpty(installPath) || !Directory.Exists(installPath))
{
    throw new Exception($"Workshop install path was not found: {installPath ?? "(null)"}");
}

string mapsFolder = Path.Combine(ThisService.RootDirectory, "csgo", "maps");
Directory.CreateDirectory(mapsFolder);

// Map-related asset extensions a CS:GO workshop map item can contain.
string[] mapExtensions = { ".bsp", ".nav", ".ain", ".txt" };

var mapFiles = Directory
    .EnumerateFiles(installPath, "*", SearchOption.AllDirectories)
    .Where(f => mapExtensions.Contains(Path.GetExtension(f), StringComparer.OrdinalIgnoreCase))
    .ToList();

if (mapFiles.Count == 0)
{
    throw new Exception($"No map files (.bsp/.nav/.ain/.txt) were found in {installPath}.");
}

foreach (var sourceFile in mapFiles)
{
    var destFile = Path.Combine(mapsFolder, Path.GetFileName(sourceFile));
    try
    {
        File.Copy(sourceFile, destFile, true);
        ScriptConsole.WriteLine($"Installed map file: csgo/maps/{Path.GetFileName(sourceFile)}");
    }
    catch (IOException e)
    {
        throw new Exception($"Failed to install csgo/maps/{Path.GetFileName(sourceFile)}, error was:\n{e.Message}");
    }
}

//refAssemblies: TCAdmin.Web.Shared.dll
// V2 origin: CS:GO "Uninstall workshop mods" (AfterCustomModUninstalled).
//
// V2 deleted csgo/maps/<FileNameNoPath>. V3 has NO `FileNameNoPath` variable.
//
// Note: in V3 the workshop UNINSTALL pipeline already deletes every file that was
// tracked (via FileSystemWatcher) when the item was installed — see
// BaseWorkshopFileTaskStepHandler.UninstallWorkshopFile. The companion install script
// (383) copies the map assets into csgo/maps, and those copies are tracked, so the
// pipeline normally removes them on its own and this event is largely redundant.
//
// This script is kept as a best-effort safety net: it derives the map file names from
// the workshop item directory (Dynamic.InstallPath) and removes any matching files
// still present in csgo/maps.
using System;
using System.IO;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string mapsFolder = Path.Combine(ThisService.RootDirectory, "csgo", "maps");
string installPath = (string)Dynamic.InstallPath;

if (string.IsNullOrEmpty(installPath) || !Directory.Exists(installPath))
{
    ScriptConsole.WriteLine($"Workshop item directory not present ({installPath ?? "(null)"}); nothing to remove from csgo/maps.");
    return;
}

string[] mapExtensions = { ".bsp", ".nav", ".ain", ".txt" };

var mapFileNames = Directory
    .EnumerateFiles(installPath, "*", SearchOption.AllDirectories)
    .Where(f => mapExtensions.Contains(Path.GetExtension(f), StringComparer.OrdinalIgnoreCase))
    .Select(Path.GetFileName)
    .Distinct();

foreach (var fileName in mapFileNames)
{
    var mapFile = Path.Combine(mapsFolder, fileName);
    try
    {
        if (File.Exists(mapFile))
        {
            File.Delete(mapFile);
            ScriptConsole.WriteLine($"Removed map file: csgo/maps/{fileName}");
        }
    }
    catch (IOException e)
    {
        throw new Exception($"Failed to delete csgo/maps/{fileName}, error was:\n{e.Message}");
    }
}
